changeSet.sql:
update COMMUNICATIONSETTINGS set STATUS = 'COMMUNICATION_REJECTED' 
where COMMUNICATIONSETTINGS.ISACTIVE = 1 
and COMMUNICATIONSETTINGS.CONTACT_ID in (select CONTACT_ID from COMMUNICATIONSETTINGS where COMMUNICATIONSETTINGS.ISACTIVE = 1 and COMMUNICATIONSETTINGS.STATUS = 'COMMUNICATION_REJECTED' and COMMUNICATIONSETTINGS.CHANNEL_TYPE = 'COMMUNICATIONCHANNEL_GLOBAL');

update COMMUNICATIONSETTINGS set STATUS = 'COMMUNICATION_ALLOWED' 
where COMMUNICATIONSETTINGS.ISACTIVE = 1 
and COMMUNICATIONSETTINGS.CONTACT_ID in (select CONTACT_ID from COMMUNICATIONSETTINGS where COMMUNICATIONSETTINGS.ISACTIVE = 1 and COMMUNICATIONSETTINGS.STATUS = 'COMMUNICATION_ALLOWED' and COMMUNICATIONSETTINGS.CHANNEL_TYPE = 'COMMUNICATIONCHANNEL_GLOBAL');
